				\usepackage{mathrsfs}
				\usepackage{upgreek}
				\setlength{\oddsidemargin}{-69pt}
				\begin{document}$$BFR/BS=MAR\cdot MS/BS$$\end{document}BFR/BS=MAR·MS/BS
